import{_ as i,o as s,c as a,ae as e}from"./chunks/framework.Dg21OTSi.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"note/AI/skill.md","filePath":"note/AI/skill.md"}'),t={name:"note/AI/skill.md"};function p(r,l,o,n,k,u){return s(),a("div",null,[...l[0]||(l[0]=[e('<h2 id="skills-是什么" tabindex="-1">skills 是什么 <a class="header-anchor" href="#skills-是什么" aria-label="Permalink to &quot;skills 是什么&quot;">​</a></h2><p>Skills 把「长期积累的经验、规则、最佳实践」封装成一套可复用、可组合、可触发的技能</p><p>你可以把Skills理解为：</p><ul><li>AI的「专业知识模块」</li><li>AI的「长期记忆 + 行为约束」</li><li>甚至是某个技术栈的「官方用法说明书（AI 版）」</li></ul><h2 id="skills-特点" tabindex="-1">skills 特点 <a class="header-anchor" href="#skills-特点" aria-label="Permalink to &quot;skills 特点&quot;">​</a></h2><p>优点：</p><ul><li>渐进式加载：先读头部源信息 -&gt; 读框架总览 -&gt; 具体框架内容</li></ul><p>缺点：</p><ul><li><p>标准统一，位置割裂。不同 AI 工具目录各异，跨平台使用不便</p></li><li><p>文件臃肿，无法渐进加载。大一统文件阻碍流动，难以分批到达</p></li><li><p>索引缺失，命名不明导致低效查询。命名混乱无索引，被迫加载多文件试错。</p></li><li><p>多 skills 冲突：过度安装的隐患。经验不足导致功能重叠，引发决策困境，效果很差。</p></li><li><p>存在相似技能时，缺乏智能提示，导致重复或冲突（未智能）</p></li><li><p>强模型 + 好 Skills：模型底子好，Skills 如虎添翼，效果拔群。</p></li><li><p>弱模型 + 好 Skills：模型能力差，Skills 难以发挥，“巧妇难为无米之炊”</p></li></ul><h2 id="skills-文件夹" tabindex="-1">skills 文件夹 <a class="header-anchor" href="#skills-文件夹" aria-label="Permalink to &quot;skills 文件夹&quot;">​</a></h2><p>头部元信息：</p><ul><li>name: 技能名称</li><li>description: 描述：何时用，提供能力</li></ul><p>正文内容</p><ul><li>技能流程</li><li>相关信息</li><li>文件说明</li></ul><p>资源文件夹（辅助内容）</p><ul><li>examples(示例)</li><li>templates(模版)</li><li>scripts（脚本）</li><li>reference.md（索引）</li></ul><h2 id="自己" tabindex="-1">自己 <a class="header-anchor" href="#自己" aria-label="Permalink to &quot;自己&quot;">​</a></h2><ul><li>现成 Skills 的烦恼：质量不一，不适用，找不到</li><li>打造我的专属 Skills，基于个人需求，快速构建</li></ul>',18)])])}const h=i(t,[["render",p]]);export{c as __pageData,h as default};
